            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/display/shop-floor"]""",
            Tags = """["shop-floor","kiosk","walkthrough"]""",
            ContentJson = """{"appRoute":"/display/shop-floor","startButtonLabel":"Tour Shop Floor","steps":[{"element":".sf-header","popover":{"title":"Shop Floor Header","description":"The header shows the page title, a kiosk search bar, font size controls, a light/dark theme toggle, and a real-time clock. All kiosk settings are saved to localStorage and persist across browser restarts.","side":"bottom"}},{"element":".sf-header__stats","popover":{"title":"Status Summary Bar","description":"Real-time counts of workers currently Working (green), On Break (yellow), Unassigned Jobs, jobs Done Today, and maintenance Alerts (red, shown only when > 0). These refresh automatically every 15 seconds.","side":"bottom"}},{"element":".sf-grid","popover":{"title":"Worker Cards Grid","description":"All workers are shown in a responsive grid. Each card has a colored left stripe (green = working, yellow = break, gray = clocked out), an avatar, the worker's name and status, elapsed time, and up to 4 assigned jobs. Tap a card to authenticate and access clock actions. You can also drag unassigned jobs onto worker cards to assign them.","side":"top"}},{"element":".sf-card","popover":{"title":"Worker Card","description":"A single worker card. The left stripe color matches the worker's clock status. The identity section shows avatar, name, short status label, and live elapsed time. Below that, assigned jobs are listed with stage color dots, job numbers, titles, and timer indicators.","side":"right"}},{"element":".sf-action-bar","popover":{"title":"Action Bar","description":"The bottom bar shows a passive scan prompt and displays scan feedback messages (e.g., 'Job 1055 — Precision Shaft Assembly' or 'Scan not recognized'). Feedback auto-dismisses after 4 seconds.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Shop Floor Field Reference",
            Slug = "shop-floor-field-reference",
            Summary = "Complete reference for the shop floor display: auth flow fields, worker card fields, job action buttons, clock actions, auto-dismiss timeouts, kiosk settings, receiving, shipping, and stage filtering.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/display/shop-floor"]""",
            Tags = """["shop-floor","kiosk","reference"]""",
            ContentJson = """{"title":"Shop Floor Field Reference","groups":[{"heading":"Authentication Flow","items":[{"label":"Scan + PIN","value":"Worker scans RFID badge or barcode → system identifies via API → PIN overlay appears → worker enters numeric PIN (min 4 digits) → submits → actions overlay opens. Uses scanLogin() auth method."},{"label":"Card Tap + Password","value":"Worker taps their name card on the grid → password overlay appears (full password, not PIN) → submits → actions overlay opens. Uses standard login() auth method."},{"label":"PIN field (scan auth)","value":"Numeric input, type=password, min 4 digits, max 8 characters. Placeholder: 'Enter your PIN'. Auto-focused when PIN phase opens."},{"label":"Password field (tap auth)","value":"Text input, type=password, max 128 characters. Placeholder: 'Enter your password'."},{"label":"Submit button","value":"Disabled when authenticating or field empty. Shows 'Verifying...' spinner (sync icon) during auth. Label: 'Submit' with login icon."},{"label":"Cancel button","value":"Returns to main dashboard. Label: 'Cancel' with arrow_back icon."},{"label":"Error messages","value":"'Invalid badge or PIN' for failed scan auth. 'Invalid password' for failed tap auth. 'PIN must be at least 4 digits' for short PINs."}]},{"heading":"Auto-Dismiss Timeouts","items":[{"label":"PIN phase timeout","value":"20 seconds. If the worker does not submit within 20 seconds, the overlay auto-cancels and returns to the main dashboard."},{"label":"Job selection timeout","value":"15 seconds. If the worker does not pick a job or skip within 15 seconds, the overlay auto-cancels and logs out."},{"label":"Actions phase auto-logout","value":"30 seconds of inactivity. Any button press resets the timer. After 30 seconds, the session is cleared and the display returns to the main dashboard."},{"label":"Data refresh interval","value":"15 seconds. Worker status, job data, and upcoming events refresh automatically on the main dashboard."},{"label":"Clock update interval","value":"1 second. The header clock and worker elapsed times update every second."},{"label":"Scan feedback auto-dismiss","value":"4 seconds. Feedback messages in the bottom bar disappear after 4 seconds."},{"label":"Action success feedback","value":"1.5 seconds. After a successful clock action, feedback is shown briefly before auto-logout. 0.8 seconds before transitioning to job picker (if applicable)."}]},{"heading":"Worker Card Fields","items":[{"label":"Status stripe (left border)","value":"Colored vertical stripe on the left edge. Green (sf-card--in) for working status, yellow (sf-card--break) for break/lunch, gray (sf-card--out) for clocked out. Color determined by ClockEventTypeService status mapping."},{"label":"Avatar","value":"AvatarComponent with size 'lg'. Shows worker initials and avatar color."},{"label":"Worker name","value":"Full name displayed in sf-card__name."},{"label":"Status label","value":"Short label from ClockEventTypeService.getShortLabel(). Displayed next to the name."},{"label":"Elapsed time","value":"Live-updating duration since worker entered current status. Format: Xs, Xm XXs, or Xh XXm XXs. Recomputed every second via tick signal."},{"label":"Assigned jobs (max 4 visible)","value":"Each job row shows: stage color dot, job number, job title, and timer icon (if active). Active-timer jobs highlighted. Overdue jobs get overdue styling."},{"label":"Overflow indicator","value":"'+N more' text when worker has more than 4 assignments."},{"label":"Drop target highlight","value":"Visual highlight (sf-card--drop-target) when dragging an unassigned job over the card."},{"label":"Feedback states","value":"Green pulse (sf-card--feedback-success) after successful action. Red pulse (sf-card--feedback-fail) after failed action."}]},{"heading":"Header Stats","items":[{"label":"Working (green)","value":"Count of workers with an active 'working' clock status. Color: var(--success)."},{"label":"On Break (yellow)","value":"Count of workers with break or lunch clock status. Color: var(--warning)."},{"label":"Unassigned","value":"Count of active jobs with no assigneeId."},{"label":"Done Today (accent)","value":"Count of jobs completed today. Color: var(--accent)."},{"label":"Alerts (red)","value":"Count of maintenance alerts. Only shown when > 0. Color: var(--error)."}]},{"heading":"Job Action Buttons (Actions Overlay)","items":[{"label":"Start Timer (play_circle)","value":"Starts tracking time against the selected job. Calls POST /time-tracking/timer/start with jobId. Disabled while any action is processing. Shows spinner during request."},{"label":"Stop Timer (stop_circle)","value":"Stops the currently running timer. Calls POST /time-tracking/timer/stop. Only shown on jobs with an active timer."},{"label":"Mark Complete (check_circle)","value":"Marks the job as complete and moves it to the next stage. Calls POST /display/shop-floor/complete-job. After success, auto-logs out after 1.2 seconds."}]},{"heading":"Clock Action Buttons (Actions Overlay)","items":[{"label":"Dynamic actions","value":"Buttons are generated from ClockEventTypeService.getAvailableActions(worker.status). Each button shows an icon and label from the clock event type definition, with a custom color via --btn-color CSS variable."},{"label":"Clock In","value":"Available when worker is clocked out. Transitions to 'working' status. If worker has no assignments after clock-in, the job picker overlay appears."},{"label":"Clock Out","value":"Available when worker is clocked in. Transitions to 'clocked out' status."},{"label":"Break / Lunch","value":"Available when worker is clocked in. Transitions to break/lunch status."},{"label":"Processing state","value":"All buttons disabled while any action is in progress. Active button shows spinning sync icon."}]},{"heading":"Dock Actions (Role-Gated)","items":[{"label":"Receive Goods (move_to_inbox)","value":"Opens the receiving overlay. Available to Admin, Manager, OfficeManager, Engineer, and ProductionWorker roles. Only shown when the worker is actively clocked in."},{"label":"Ship Goods (local_shipping)","value":"Opens the shipping overlay. Available to Admin, Manager, and OfficeManager roles. Only shown when the worker is actively clocked in."},{"label":"Receiving overlay — PO selection","value":"Lists open purchase orders (status: Submitted, Acknowledged, PartiallyReceived) with receivable lines. Shows PO number, vendor name, and line count."},{"label":"Receiving overlay — line confirmation","value":"Per-line quantity adjustment with +/- buttons. Shows part number, description, remaining quantity. Optional bin location select dropdown."},{"label":"Receiving overlay — Receive All button","value":"Submits all lines with qty > 0. Shows spinner during submission. Auto-logs out after 1.5 seconds on success."},{"label":"Shipping overlay — shipment selection","value":"Lists pending and packed shipments. Shows shipment number, customer name, sales order number, and status chip."},{"label":"Shipping overlay — shipment detail","value":"Shows shipment number, customer, SO number, carrier, tracking number, and line items with descriptions and quantities."},{"label":"Print Packing Slip button","value":"Opens the packing slip PDF in a new tab via GET /shipments/{id}/packing-slip."},{"label":"Mark Shipped button","value":"Confirms shipment. Shows spinner during submission. Auto-logs out after 1.5 seconds on success."}]},{"heading":"Kiosk Settings (Header Controls)","items":[{"label":"Font size decrease (text_decrease)","value":"Reduces font size by one step. Disabled at minimum (12px, index 0). Steps: 12, 14, 16, 18, 20px. Applied via CSS zoom. Persisted to localStorage key 'sf-font-index'."},{"label":"Font size display","value":"Shows current font size in pixels (e.g., '14px')."},{"label":"Font size increase (text_increase)","value":"Increases font size by one step. Disabled at maximum (20px, index 4)."},{"label":"Theme toggle (dark_mode / light_mode)","value":"Switches between light and dark themes. Icon changes based on current theme. Persisted to localStorage key 'sf-theme'. Applied via data-theme attribute on the host element."},{"label":"Live clock","value":"Displays current time in HH:MM:SS AM/PM format. Updates every second."}]},{"heading":"Stage Filtering (IsShopFloor)","items":[{"label":"IsShopFloor flag","value":"Boolean on TrackType and JobStage entities. Controls which stages appear on the shop floor display. Only stages with IsShopFloor = true show their jobs."},{"label":"Purpose","value":"Filters out non-physical stages (quoting, invoicing, payment) that are irrelevant to production floor workers."},{"label":"Configuration","value":"Set via Admin → Track Types. Each stage within a track type can be individually toggled for shop floor visibility."}]},{"heading":"Job Selection Overlay","items":[{"label":"Trigger","value":"Appears automatically after clock-in if the worker has no assigned jobs. Shown after 0.8-second feedback delay."},{"label":"Job list","value":"Shows all unassigned jobs with stage color dot, job number, title, stage name, and priority. Each job is a clickable button."},{"label":"Assign action","value":"Clicking a job assigns it to the worker via POST /display/shop-floor/assign-job. Auto-logs out after 0.8 seconds on success."},{"label":"Skip button","value":"Skips job selection and logs out. Icon: skip_next."},{"label":"Empty state","value":"Shows 'No unassigned jobs available' with work_off icon when no jobs are available."}]},{"heading":"Drag-and-Drop Job Assignment","items":[{"label":"Drag source","value":"Unassigned job cards in the unassigned jobs section. Each card has a drag_indicator handle icon and draggable='true'."},{"label":"Drop target","value":"Worker cards in the main grid. Visual highlight appears when dragging over a card."},{"label":"Assignment","value":"Dropping a job on a worker card calls POST /display/shop-floor/assign-job with jobId and userId. Data refreshes after assignment."},{"label":"Drag data","value":"Job ID transferred via dataTransfer with type 'application/x-job-id'."}]},{"heading":"Scan Identification","items":[{"label":"API endpoint","value":"POST /display/shop-floor/identify-scan with { scanValue }. Returns ScanIdentification with scanType, entityId, entityNumber, entityTitle."},{"label":"Scan types","value":"employee (→ PIN phase), job (→ feedback message), storage-location (→ opens the location-contents overlay), sales-order (→ 'tap your badge to ship' prompt), unknown (→ 'Scan not recognized')."},{"label":"Storage-location scan","value":"Scanning a storage-location barcode on the main display opens the Location View overlay (app-scan-location-view) listing everything in that bin — each row shows the item name, lot number (if any), and quantity, with a Scan button to drill into that part's actions."},{"label":"Fallback","value":"If identification API fails, the scan value is treated as an employee badge and the PIN overlay opens."},{"label":"Scanner context","value":"ScannerService context set to 'shop-floor'. Only processes scans during the main phase — ignores scans during overlays."}]},{"heading":"Reverse / Undo a Scan Action","items":[{"label":"Where","value":"The Recent Scan Actions (undo) panel, opened from the main shop floor display. Lists scan actions from the last 6 hours."},{"label":"Lookback window","value":"6 hours. Only actions within the last 6 hours are eligible to reverse; older entries drop off the undo list (but remain in the full Daily Scan Log)."},{"label":"Per-entry row","value":"Shows time (HH:mm), who did it, the action type, quantity ×, part number, from→to locations, and any related entity (job/PO/shipment)."},{"label":"Reverse button","value":"Each not-yet-reversed entry has a Reverse button. Already-reversed entries show a 'Reversed' label instead and cannot be reversed again."},{"label":"PIN gate","value":"Clicking Reverse opens a PIN prompt. A valid PIN is required to authorize the reversal — this is a supervised correction, not a free undo. A wrong PIN shows 'Failed to reverse action. Check your PIN.'"},{"label":"Effect","value":"A successful reversal posts to POST /scanner/reverse with the scan-action-log id + PIN, backs out the movement (e.g. a Move is moved back to its from-location), shows a confirmation snackbar, and reloads the list."},{"label":"Today count","value":"The panel header shows a count of scan actions performed today."}]},{"heading":"Daily Scan Log","items":[{"label":"Route","value":"/display/shop-floor/scan-log (also openable as a panel from the main display)."},{"label":"Purpose","value":"A read-only, filterable record of all scan activity for a chosen day — the audit view that complements the 6-hour undo panel."},{"label":"Date filter","value":"Date picker, defaults to today. Pick any date to see that day's activity."},{"label":"Action Type filter","value":"All, Move, Count (CycleCount), Receive, Ship, Issue. Narrows the table to one action type."},{"label":"Summary line","value":"Shows 'N scans today' plus a breakdown (e.g. '4 moves, 2 receives, 1 issue') computed from the filtered rows."},{"label":"Columns","value":"Time (HH:mm:ss), Action (chip), Part, Qty, From, To, Related, Status. Reversed entries show a red 'Reversed' chip in the Status column."},{"label":"Empty state","value":"'No scan activity for this date' with a history icon when the filters return nothing."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Shop Floor Knowledge Check",
